def validate_hmac_hash(data, shared_secret):
    payload_hash = request.headers.get('X-Hub-Signature')
    if not payload_hash or not isinstance(payload_hash, str):
        return False
    secret = bytes(shared_secret, 'UTF-8')
    hash_obj = hmac.new(secret, msg=data, digestmod=hashlib.sha1)
    gen_hash = 'sha1=' + hash_obj.hexdigest()
    return hmac.compare_digest(gen_hash, payload_hash)